catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
   if (isLoading || newValue == '') {
      return;
   }

   //Type appropriate comment here, and begin script below

   var ga = new GlideAjax('GetWorkspaceLocation');
    ga.addParam('sysparm_name', 'getWorkspaceLocation');
    ga.addParam('sysparm_workspace_id', newValue);

    ga.getXMLAnswer(function(response) {
        if (response) {
            g_form.setValue('location', JSON.parse(response).location);

			if (JSON.parse(response).image) {
				var image_tag_with_url = '<img src="https://dev184546.service-now.com/' + JSON.parse(response).image + '.iix" style="max-width:300px;"/>';

				g_form.setValue('workspace_preview', image_tag_with_url);
			} else {
				g_form.setValue('workspace_preview', "");
			}
        }
    });

